      const parsed = saved ? JSON.parse(saved) : INITIAL_SITE_CONFIG;
      // Merge: INITIAL tiene prioridad para campos nuevos, parsed tiene prioridad para campos existentes editados
      return { ...INITIAL_SITE_CONFIG, ...parsed };
