  useEffect(() => {
    setProducts(prevProducts => {
       const currentIds = new Set(prevProducts.map(p => p.id));
       // Buscar productos en INITIAL_PRODUCTS que NO estén en el estado actual
       const missingProducts = INITIAL_PRODUCTS.filter(p => !currentIds.has(p.id));

       if (missingProducts.length > 0) {
