    name: '',
    idRuc: '',      // Mapped to IDRUC
    email: '',      // Mapped to CORREO
    phone: '',      // Mapped to CELULAR
    landline: '',   // Mapped to TELEFONO
    address: '',    // Mapped to DIRECCION
    province: '',   // Mapped to PROVINCIA
  });

